def test_surface_pca_Garabedian_with_vmec():
    vmec = Vmec(os.path.join(DATA_DIR, "input.vmec"))

    nfp = 3
    major_radius = 2.3
    minor_radius = 0.5
    dimension = 10

    pca_surface = SurfacePCAGarabedian(
        nfp=nfp,
        major_radius=major_radius,
        minor_radius=minor_radius,
        dimension=dimension,
    )
    vmec.boundary = pca_surface
    vmec.indata.nfp = nfp  # Vmec++ does not automatically get nfp from the boundary surface!

    vmec.run()
    np.testing.assert_equal(vmec.wout.nfp, nfp)
    np.testing.assert_allclose(vmec.wout.Rmajor_p, major_radius, rtol=0.007)
    np.testing.assert_allclose(vmec.wout.Aminor_p, minor_radius, rtol=0.1)
    print("iota:", list(vmec.wout.iotaf))
    np.testing.assert_allclose(vmec.wout.iotaf[0], 0.5077877135540572)
    np.testing.assert_allclose(vmec.wout.iotaf[-1], 0.5496170499988579)
    
